import heapq
from collections import defaultdict

class DSU:
    def __init__(self, size):
        self.parent = list(range(size + 1))
        self.rank = [1] * (size + 1)

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    dsu = DSU(c)
    for u, v in connections:
        dsu.union(u, v)

    component_heaps = defaultdict(list)
    for node in range(1, c + 1):
        root = dsu.find(node)
        heapq.heappush(component_heaps[root], node)

    active = [True] * (c + 1)

    result = []
    for query in queries:
        if query[0] == 1:
            x = query[1]
            if active[x]:
                result.append(x)
            else:
                root = dsu.find(x)
                while component_heaps[root]:
                    top = component_heaps[root][0]
                    if active[top]:
                        break
                    else:
                        heapq.heappop(component_heaps[root])
                if not component_heaps[root]:
                    result.append(-1)
                else:
                    result.append(component_heaps[root][0])
        else:
            x = query[1]
            active[x] = False
    return result
